{# module://os2forms_fordelingskomponent/resources/SP/SF2900_XSD/SP246.xsd #}

{% macro personnummer(value) -%}
{{ 'urn:oio:cpr:%010d'|format(value) }}
{%- endmacro %}

{% macro telefonnummer(value) -%}
  {{ '%08d'|format(value) }}
{%- endmacro %}

{% macro date(value) -%}
{{ value|date('Y-m-d') }}
{%- endmacro %}

{% macro max_laengde_strings_200(value) -%}
{{ value|trim|slice(0, 200) }}
{%- endmacro %}

{% macro positive_integer(value) -%}
{%- set value = max(1, value|number_format(0, '', '')) -%}
{{ '%d'|format(value) }}
{%- endmacro %}

{% macro positive_integer_type_or_empty(value) -%}
{%- if value is not empty -%}
{%- set value = max(1, value|number_format(0, '', '')) -%}
{{ '%d'|format(value) }}
{%- endif -%}
{%- endmacro %}

{# number_format (https://twig.symfony.com/doc/3.x/filters/number_format.html) will cast anything (that can be casted to a float) to a float before formatting
(cf. https://github.com/twigphp/Twig/blob/99d95dd6b8b0cc3c2397d15d45a4bb87eff89ddc/src/Extension/CoreExtension.php#L698) #}

{# Strip thousand and decimal separators (from Danish floats); compute with 4 decimals #}
{% macro decimal_value(value) -%}
{%- set value = value|replace({'.': ''})|replace({',': '.'})|number_format(4, '', '') -%}
{{ value }}
{%- endmacro %}

{% macro positiv_decimal_type(value) -%}
{%- set value = max(0.01, value|replace({'.': ''})|replace({',': '.'})|number_format(4, '', '')) -%}
{{ value|number_format(2, '.', '') }}
{%- endmacro %}

{% macro decimal_type(value) -%}
{%- set value = value|replace({'.': ''})|replace({',': '.'})|number_format(4, '', '') -%}
{{ value|number_format(2, '.', '') }}
{%- endmacro %}


